const xml = $input.first().json.body || $input.first().json.data || '';
const results = [];

const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;

while ((match = itemRegex.exec(xml)) !== null) {
  const item = match[1];

  const title = (item.match(/<title>([\s\S]*?)<\/title>/) || [])[1] || '';
  const link = (item.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || '';
  const pubDate = (item.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
  const source = (item.match(/<source[^>]*>([\s\S]*?)<\/source>/) || [])[1] || '';
  const description = (item.match(/<description>([\s\S]*?)<\/description>/) || [])[1] || '';

  if (!title || !link) continue;
  if (!source.toLowerCase().includes('reuters')) continue;

  results.push({
    json: {
      title: title.replace(' - Reuters', '').trim(),
      url: link.trim(),
      link: link.trim(),
      creator: '',
      content: description.replace(/<[^>]*>/g, '').trim().substring(0, 2000),
      contentSnippet: description.replace(/<[^>]*>/g, '').trim().substring(0, 500),
      guid: link.trim(),
      categories: [],
      isoDate: pubDate ? new Date(pubDate).toISOString() : '',
      pubDate: pubDate.trim(),
      source: 'Reuters',
      category: 'news',
      status: 'raw',
      createdAt: new Date().toISOString(),
      __sourceName: 'RSS — Reuters'
    }
  });

  if (results.length >= 15) break;
}

return results;

const crypto = require('crypto');
const results = [];

for (const item of $input.all()) {
  const { url, title } = item.json;
  if (!url && !title) continue;

  const raw = `${url}::${title}`.toLowerCase().trim();
  const uniqueKey = crypto.createHash('sha256').update(raw).digest('hex');

  results.push({ json: { ...item.json, uniqueKey } });
}

return results;

