const results = [];

for (const item of $input.all()) {
  const raw = item.json;

  const title = (raw.title || '').toString().replace(/<[^>]*>/g, '').trim();
  const link = (raw.link || raw.url || raw.guid || '').toString().trim();
  if (!title || !link) continue;

  const creator = (raw.creator || raw['dc:creator'] || raw.author || '').toString().trim();
  const content = (raw.content || raw['content:encoded'] || raw.description || '').toString().replace(/<[^>]*>/g, '').trim().substring(0, 2000);
  const contentSnippet = (raw.contentSnippet || raw.description || '').toString().replace(/<[^>]*>/g, '').trim().substring(0, 500);
  const guid = (raw.guid || raw.id || link).toString().trim();
  const categories = Array.isArray(raw.categories) ? raw.categories : raw.category ? [raw.category] : [];

  const rawDate = raw.isoDate || raw.pubDate || raw.date || raw.published || '';
  let isoDate = '';
  if (rawDate) {
    const parsed = new Date(rawDate);
    if (!isNaN(parsed.getTime())) isoDate = parsed.toISOString();
  }

  results.push({
    json: {
      title,
      url: link,
      link,
      creator,
      content,
      contentSnippet,
      guid,
      categories,
      isoDate,
      pubDate: raw.pubDate || isoDate,
      source: 'TechCrunch',
      category: 'tech',
      status: 'raw',
      createdAt: new Date().toISOString(),
      __sourceName: 'RSS — TechCrunch'
    }
  });
}

return results;

